class Solution {
public:
    int longestPalindrome(string s, string t) {
        int n = s.size(), m = t.size();
        int best = 0;
        // odd length: center in s and t
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int l = 0;
                while (i - l >= 0 && j + l < m && s[i - l] == t[j + l]) ++l;
                best = max(best, 2 * l - 1);
            }
        }
        // even length: center between s and t
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int l = 0;
                while (i - l >= 0 && j + l < m && s[i - l] == t[j + l]) ++l;
                best = max(best, 2 * l);
            }
        }
        // odd length: center in t and s
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                int l = 0;
                while (i - l >= 0 && j + l < n && t[i - l] == s[j + l]) ++l;
                best = max(best, 2 * l - 1);
            }
        }
        // even length: center between t and s
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                int l = 0;
                while (i - l >= 0 && j + l < n && t[i - l] == s[j + l]) ++l;
